// Validate required environment variables
const required = ['WHATSAPP_PHONE_ID', 'UPI_ID'];
const missing = required.filter(v => !$env[v]);

if (missing.length > 0) {
  throw new Error(`❌ Missing required environment variables: ${missing.join(', ')}`);
}

// Validate webhook payload structure
const entry = $input.item.json.entry?.[0];
if (!entry || !entry.changes?.[0]?.value) {
  throw new Error('Invalid WhatsApp webhook payload structure');
}

// Return the input unchanged
return $input.item.json;

// Rate limiting: max 10 messages per minute per user
const phone = $input.item.json.from;
const now = Date.now();

// Initialize or get rate limit data from static storage
if (!$static.rateLimits) {
  $static.rateLimits = {};
}

if (!$static.rateLimits[phone]) {
  $static.rateLimits[phone] = [];
}

// Remove messages older than 1 minute
$static.rateLimits[phone] = $static.rateLimits[phone].filter(t => now - t < 60000);

// Check if rate limit exceeded
if ($static.rateLimits[phone].length >= 10) {
  return {
    ...$input.item.json,
    error: 'RATE_LIMIT',
    error_msg: '⏸️ Please slow down. You can send up to 10 messages per minute.'
  };
}

// Add current message timestamp
$static.rateLimits[phone].push(now);

// Clean up old users (keep only last 1000)
const allPhones = Object.keys($static.rateLimits);
if (allPhones.length > 1000) {
  allPhones.slice(0, -1000).forEach(p => delete $static.rateLimits[p]);
}

return $input.item.json;

const raw = ($input.item.json.raw_text || '').toUpperCase();
const clean = raw.replace(/[^A-Z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
const interactive = $input.item.json.button_id || $input.item.json.list_id || '';
return { 
  ...($input.item.json), 
  text: clean, 
  action: interactive.toUpperCase(),
  timestamp: Date.now()
};

// SQL Injection Protection - Sanitize user inputs
const phone = ($input.item.json.from || '').toString();
const text = ($input.item.json.text || '').toString();
const action = ($input.item.json.action || '').toString();

// Validate phone number format (only digits, +, and -)
const phoneRegex = /^[+\d-]+$/;
if (!phoneRegex.test(phone)) {
  return {
    ...$input.item.json,
    error: 'INVALID_PHONE',
    error_msg: '❌ Invalid phone number format detected. Please contact support.'
  };
}

// Sanitize for SQL (escape single quotes)
const sanitizedPhone = phone.replace(/'/g, "''");

// Limit phone length (E.164 format max is 15 digits + country code)
if (sanitizedPhone.length > 20) {
  return {
    ...$input.item.json,
    error: 'PHONE_TOO_LONG',
    error_msg: '❌ Phone number too long. Please contact support.'
  };
}

// Return sanitized data
return {
  ...$input.item.json,
  from: sanitizedPhone,
  from_original: phone,
  _sanitized: true
};

const dbResult = $input.all()[0]?.json || {};
const phone = $input.first().json.from;
const now = Date.now();

let session = {
  phone: phone,
  table: null,
  cart: [],
  customer_name: $input.first().json.contact_name,
  last_seen: now,
  session_started: now,
  total_orders: 0,
  preferences: {}
};

if (dbResult.phone) {
  // Safe JSON parsing with error handling
  let cart = [];
  let preferences = {};
  try {
    cart = JSON.parse(dbResult.cart || '[]');
    if (!Array.isArray(cart)) cart = [];
  } catch (e) {
    console.error('Failed to parse cart:', e);
    cart = [];
  }

  try {
    preferences = JSON.parse(dbResult.preferences || '{}');
    if (typeof preferences !== 'object') preferences = {};
  } catch (e) {
    console.error('Failed to parse preferences:', e);
    preferences = {};
  }

  // Safe date parsing
  const lastSeenTime = new Date(dbResult.last_seen).getTime();
  const expired = isNaN(lastSeenTime) || (now - lastSeenTime) > 900000;

  if (!expired) {
    session = {
      ...dbResult,
      cart: cart,
      preferences: preferences,
      last_seen: now
    };
  } else {
    session.total_orders = dbResult.total_orders || 0;
  }
}

return { 
  ...$input.first().json, 
  session: session,
  is_new_session: !dbResult.phone || (now - new Date(dbResult.last_seen).getTime()) > 900000
};

