const session = $input.item.json.session;
const phone = $input.item.json.from;

// PREVENT DUPLICATE ORDERS: Use $static storage (in-memory)
if (!$static.lastOrderTimes) {
  $static.lastOrderTimes = {};
}

if ($static.lastOrderTimes[phone]) {
  const timeSinceLastOrder = Date.now() - $static.lastOrderTimes[phone];
  if (timeSinceLastOrder < 60000) { // 60 seconds
    const waitSeconds = Math.ceil((60000 - timeSinceLastOrder) / 1000);
    return { 
      ...$input.item.json, 
      error: 'ORDER_TOO_SOON', 
      error_msg: `⏸️ *Please wait ${waitSeconds} seconds*\n\nYou can place another order in ${waitSeconds}s\n\nNeed to modify? Type CART` 
    };
  }
}

if (!session.cart || !session.cart.length) {
  return { 
    ...$input.item.json, 
    error: 'EMPTY_CART', 
    error_msg: '🛒 *Cart is Empty!*\n\n📋 How to order:\n1️⃣ Type MENU to browse\n2️⃣ Send codes like: B1 2\n3️⃣ Type CONFIRM to checkout\n\nNeed help? Type HELP' 
  };
}

const orderId = 'ORD' + Date.now().toString().slice(-6);
const subtotal = session.cart.reduce((s, i) => s + (i.price * i.qty), 0);
const taxRate = parseFloat($env.TAX_RATE || '0.05');
const tax = subtotal * taxRate;
const total = subtotal + tax;

const orderData = {
  order_id: orderId,
  table: session.table,
  phone: $input.item.json.from,
  customer_name: session.customer_name,
  items: session.cart,
  subtotal: subtotal,
  tax: tax,
  total: total,
  status: 'pending_payment',
  timestamp: new Date().toISOString(),
  special_requests: session.special_requests || null
};

// Save order time to $static storage
$static.lastOrderTimes[phone] = Date.now();

// Clean up old entries (keep only last 1000 users)
const allPhones = Object.keys($static.lastOrderTimes);
if (allPhones.length > 1000) {
  allPhones.slice(0, -1000).forEach(p => delete $static.lastOrderTimes[p]);
}

return { 
  ...$input.item.json, 
  order: orderData
};

// Generate UPI QR code URL using UPI deep link format
const upiId = $env.UPI_ID || 'restaurant@paytm';
const merchantName = ($env.RESTAURANT_NAME || 'Restaurant').replace(/[^a-zA-Z0-9\s]/g, '');
const amount = $input.item.json.order.total.toFixed(2);
const orderId = $input.item.json.order.order_id;

// UPI payment string
const upiString = `upi://pay?pa=${upiId}&pn=${encodeURIComponent(merchantName)}&am=${amount}&tn=${encodeURIComponent('Order ' + orderId)}&cu=INR`;

// Generate QR code using API
const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=400x400&data=${encodeURIComponent(upiString)}`;

return { 
  ...$input.item.json, 
  upi_string: upiString,
  qr_url: qrUrl,
  upi_id: upiId
};

